2.   Fetch,
3.   getFetchDefault,
4.   ILOidcLocation,
5.   OidcClient,
6.   OidcConfiguration,
7.   OidcLocation,
8. } from '@axa-fr/oidc-client';
9. import { ComponentType, FC, PropsWithChildren, useEffect, useState } from 'react';
10. 
11. import AuthenticatingError from './core/default-component/AuthenticateError.component.js';
12. import {
13.   Authenticating,
14.   CallBackSuccess,
15.   Loading,
