17. } from './core/default-component/index.js';
18. import ServiceWorkerNotSupported from './core/default-component/ServiceWorkerNotSupported.component.js';
19. import OidcRoutes from './core/routes/OidcRoutes.js';
20. import { CustomHistory } from './core/routes/withRouter.js';
21. 
22. export type oidcContext = {
23.   (name?: string): OidcClient;
24. };
25. 
26. const defaultEventState = { name: '', data: null };
27. 
28. export type OidcProviderProps = {
29.   callbackSuccessComponent?: ComponentType<any>;
30.   sessionLostComponent?: ComponentType<any>;
31.   authenticatingComponent?: ComponentType<any>;
32.   authenticatingErrorComponent?: ComponentType<any>;
33.   loadingComponent?: ComponentType<any>;
34.   serviceWorkerNotSupportedComponent?: ComponentType<any>;
35.   configurationName?: string;
36.   configuration?: OidcConfiguration;
37.   children: any;
38.   onSessionLost?: () => void;
39.   onLogoutFromAnotherTab?: () => void;
40.   onLogoutFromSameTab?: () => void;
41.   withCustomHistory?: () => CustomHistory;
42.   onEvent?: (configuration: string, name: string, data: any) => void;
43.   getFetch?: () => Fetch;
44.   location?: ILOidcLocation;
45. };
46. 
47. export type OidcSessionProps = {
48.   configurationName: string;
49.   loadingComponent: PropsWithChildren<any>;
50. };
51. 
52. const OidcSession: FC<PropsWithChildren<OidcSessionProps>> = ({
53.   loadingComponent,
54.   children,
55.   configurationName,
56. }) => {
57.   const [isLoading, setIsLoading] = useState(true);
58.   const getOidc = OidcClient.get;
59.   const oidc = getOidc(configurationName);
60.   useEffect(() => {
61.     let isMounted = true;
62.     if (oidc) {
63.       oidc.tryKeepExistingSessionAsync().then(() => {
64.         if (isMounted) {
65.           setIsLoading(false);
66.         }
67.       });
68.     }
69.     return () => {
70.       isMounted = false;
71.     };
72.   }, [configurationName]);
73.   const LoadingComponent = loadingComponent;
74.   return (
75.     <>{isLoading ? <LoadingComponent configurationName={configurationName} /> : <>{children}</>}</>
76.   );
77. };
78. 
79. const Switch = ({ isLoading, loadingComponent, children, configurationName }) => {
80.   const LoadingComponent = loadingComponent;
81.   if (isLoading) {
82.     return <LoadingComponent configurationName={configurationName}>{children}</LoadingComponent>;
83.   }
84.   return <>{children}</>;
85. };
86. 
87. export const OidcProvider: FC<PropsWithChildren<OidcProviderProps>> = ({
88.   children,
89.   configuration,
90.   configurationName = 'default',
91.   callbackSuccessComponent = CallBackSuccess,
92.   authenticatingComponent = Authenticating,
93.   loadingComponent = Loading,
94.   serviceWorkerNotSupportedComponent = ServiceWorkerNotSupported,
95.   authenticatingErrorComponent = AuthenticatingError,
96.   sessionLostComponent = SessionLost,
97.   onSessionLost = null,
98.   onLogoutFromAnotherTab = null,
99.   onLogoutFromSameTab = null,
100.   withCustomHistory = null,
101.   onEvent = null,
102.   getFetch = null,
103.   location = null,
104. }) => {
105.   if (configuration && configuration.redirect_uri && configuration.silent_redirect_uri) {
106.     if (configuration.redirect_uri === configuration.silent_redirect_uri) {
107.       throw new Error('redirect_uri and silent_redirect_uri must be different');
108.     }
109.   }
110. 
111.   const getOidc = (configurationName = 'default') => {
112.     return OidcClient.getOrCreate(getFetch ?? getFetchDefault, location ?? new OidcLocation())(
113.       configuration,
114.       configurationName,
115.     );
116.   };
117. 
118.   const loading = false;
119.   const [event, setEvent] = useState(defaultEventState);
120.   const [currentConfigurationName, setConfigurationName] = useState(configurationName);
121. 
122.   useEffect(() => {
123.     const oidc = getOidc(configurationName);
124.     const newSubscriptionId = oidc.subscribeEvents((name, data) => {
125.       if (onEvent) {
126.         onEvent(configurationName, name, data);
127.       }
128.     });
129.     return () => {
130.       const previousOidc = getOidc(configurationName);
131.       previousOidc.removeEventSubscription(newSubscriptionId);
132.     };
133.   }, [configurationName, onEvent]);
134. 
135.   useEffect(() => {
136.     const oidc = getOidc(configurationName);
137.     const newSubscriptionId = oidc.subscribeEvents((name, data) => {
138.       if (
139.         name === OidcClient.eventNames.refreshTokensAsync_error ||
140.         name === OidcClient.eventNames.syncTokensAsync_error
141.       ) {
142.         if (onSessionLost != null) {
143.           onSessionLost();
144.           return;
145.         }
146.         setEvent({ name, data });
147.       } else if (name === OidcClient.eventNames.logout_from_another_tab) {
148.         if (onLogoutFromAnotherTab != null) {
149.           onLogoutFromAnotherTab();
150.           return;
151.         }
152.         setEvent({ name, data });
153.       } else if (name === OidcClient.eventNames.logout_from_same_tab) {
154.         if (onLogoutFromSameTab != null) {
155.           onLogoutFromSameTab();
156.         }
157.         // setEvent({name, data});
158.       } else if (
159.         name === OidcClient.eventNames.loginAsync_begin ||
160.         name === OidcClient.eventNames.loginCallbackAsync_end ||
161.         name === OidcClient.eventNames.loginAsync_error ||
162.         name === OidcClient.eventNames.loginCallbackAsync_error
163.       ) {
164.         setEvent({ name, data });
165.       } else if (
166.         name === OidcClient.eventNames.service_worker_not_supported_by_browser &&
167.         configuration.service_worker_only === true
168.       ) {
169.         setEvent({ name, data });
170.       }
171.     });
172. 
173.     queueMicrotask(() => {
174.       setConfigurationName(configurationName);
175.     });
176. 
177.     return () => {
178.       const previousOidc = getOidc(configurationName);
179.       previousOidc.removeEventSubscription(newSubscriptionId);
180.       setEvent(defaultEventState);
181.     };
182.   }, [configuration, configurationName]);
183. 
184.   const SessionLostComponent = sessionLostComponent;
185.   const AuthenticatingComponent = authenticatingComponent;
186.   const LoadingComponent = loadingComponent;
187.   const ServiceWorkerNotSupportedComponent = serviceWorkerNotSupportedComponent;
188.   const AuthenticatingErrorComponent = authenticatingErrorComponent;
189. 
190.   const isLoading = loading || currentConfigurationName !== configurationName;
191.   const oidc = getOidc(configurationName);
192.   const eventName = event.name;
193.   switch (eventName) {
194.     case OidcClient.eventNames.service_worker_not_supported_by_browser:
195.       return (
196.         <Switch
197.           loadingComponent={LoadingComponent}
198.           isLoading={isLoading}
199.           configurationName={configurationName}
200.         >
201.           <ServiceWorkerNotSupportedComponent configurationName={configurationName} />
202.         </Switch>
203.       );
204.     case OidcClient.eventNames.loginAsync_begin:
205.       return (
206.         <Switch
207.           loadingComponent={LoadingComponent}
208.           isLoading={isLoading}
209.           configurationName={configurationName}
210.         >
211.           <AuthenticatingComponent configurationName={configurationName} />
212.         </Switch>
213.       );
214.     case OidcClient.eventNames.loginAsync_error:
215.     case OidcClient.eventNames.loginCallbackAsync_error:
216.       return (
217.         <Switch
218.           loadingComponent={LoadingComponent}
219.           isLoading={isLoading}
220.           configurationName={configurationName}
221.         >
222.           <AuthenticatingErrorComponent configurationName={configurationName} />
223.         </Switch>
224.       );
225.     case OidcClient.eventNames.refreshTokensAsync_error:
226.     case OidcClient.eventNames.syncTokensAsync_error:
227.     case OidcClient.eventNames.logout_from_another_tab:
228.       return (
229.         <Switch
230.           loadingComponent={LoadingComponent}
231.           isLoading={isLoading}
232.           configurationName={configurationName}
233.         >
234.           <SessionLostComponent configurationName={configurationName} />
235.         </Switch>
236.       );
237.     default:
238.       return (
239.         <Switch
240.           loadingComponent={LoadingComponent}
241.           isLoading={isLoading}
242.           configurationName={configurationName}
243.         >
244.           <OidcRoutes
245.             redirect_uri={oidc.configuration.redirect_uri}
246.             silent_redirect_uri={oidc.configuration.silent_redirect_uri}
247.             silent_login_uri={oidc.configuration.silent_login_uri}
248.             callbackSuccessComponent={callbackSuccessComponent}
249.             callbackErrorComponent={authenticatingErrorComponent}
250.             authenticatingComponent={authenticatingComponent}
251.             configurationName={configurationName}
252.             withCustomHistory={withCustomHistory}
253.             location={location ?? new OidcLocation()}
254.           >
255.             <OidcSession loadingComponent={LoadingComponent} configurationName={configurationName}>
256.               {children}
257.             </OidcSession>
258.           </OidcRoutes>
259.         </Switch>
260.       );
261.   }
262. };
263. 
264. export default OidcProvider;
