    get: vi.fn(),
  },
  getPath: (href: string) => {
    try {
      return new URL(href).pathname;
    } catch {
      return href;
    }
  },
}));

vi.mock('../routes/withRouter.js', () => ({
  getCustomHistory: vi.fn(),
}));

