           setIsError(true);
         }
       }
     };

     const timeoutId = setTimeout(() => {
       if (isMounted) {
         console.warn(
           `Callback navigation did not complete within ${navigationTimeoutMs}ms. Setting error state.`,
         );
         setIsError(true);
       }
